class Solution:
    def nextGreaterElements(self, nums):
        n = len(nums)
        res = [-1] * n
        for i in range(n):
            for step in range(1, n):
                j = (i + step) % n
                if nums[j] > nums[i]:
                    res[i] = nums[j]
                    break
        return res

